import React, { useState, FC, PropsWithChildren } from 'react';

// --- TYPE DEFINITIONS ---
type FormData = {
  addressFrom: string;
  addressTo: string;
  estimateMethod: 'quick' | 'detailed';
  roomCount: number;
  inventory: { name: string; quantity: number }[];
  floorFrom: string;
  floorTo: string;
  liftFrom: boolean;
  liftTo: boolean;
  moveDate: string;
  dateIsFlexible: boolean;
  services: {
    packing: boolean;
    cleaning: boolean;
    storage: boolean;
  };
  contact: {
    name: string;
    email: string;
    phone: string;
  };
};

// --- SVG ICONS (self-contained for portability) ---
const SvgIcon = ({ svg }: { svg: string }) => <div dangerouslySetInnerHTML={{ __html: svg }} />;

const ArrowLeftIcon = () => <SvgIcon svg='<svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke-width="2" stroke="currentColor" class="w-5 h-5"><path stroke-linecap="round" stroke-linejoin="round" d="M10.5 19.5L3 12m0 0l7.5-7.5M3 12h18" /></svg>' />;
const ArrowRightIcon = () => <SvgIcon svg='<svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke-width="2" stroke="currentColor" class="w-5 h-5"><path stroke-linecap="round" stroke-linejoin="round" d="M13.5 4.5L21 12m0 0l-7.5 7.5M21 12H3" /></svg>' />;
const CheckIcon = () => <SvgIcon svg='<svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke-width="3" stroke="currentColor" class="w-4 h-4 text-white"><path stroke-linecap="round" stroke-linejoin="round" d="M4.5 12.75l6 6 9-13.5" /></svg>' />;
const AstagIcon = () => <SvgIcon svg='<svg viewBox="0 0 100 40" class="h-8 w-auto"><text x="50" y="28" font-size="24" font-weight="bold" fill="#4A5568" text-anchor="middle" font-family="Arial">ASTAG</text></svg>' />;
const SwissFlagIcon = () => <SvgIcon svg='<svg viewBox="0 0 40 40" class="h-8 w-8"><rect width="40" height="40" fill="#D52B1E"/><rect x="8" y="16" width="24" height="8" fill="white"/><rect x="16" y="8" width="8" height="24" fill="white"/></svg>' />;
const ShieldIcon = () => <SvgIcon svg='<svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke-width="2" stroke="currentColor" class="h-8 w-8 text-gray-500"><path stroke-linecap="round" stroke-linejoin="round" d="M9 12.75L11.25 15 15 9.75m-3-7.036A11.959 11.959 0 013.598 6 11.99 11.99 0 003 9.749c0 5.592 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.31-.21-2.571-.598-3.751h-.152c-3.196 0-6.1-1.248-8.25-3.286zm0 13.036h.008v.008h-.008v-.008z" /></svg>' />;

// --- SHARED COMPONENTS (as defined in the request) ---

interface PrimaryButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  fullWidth?: boolean;
}

const PrimaryButton: FC<PropsWithChildren<PrimaryButtonProps>> = ({ children, fullWidth = false, ...props }) => {
  // Inspired by v1 CTA Design: large, inviting, clear
  return (
    <button
      {...props}
      className={`flex items-center justify-center gap-3 px-8 py-4 text-lg font-bold text-white bg-green-500 rounded-lg shadow-lg hover:bg-green-600 focus:outline-none focus:ring-4 focus:ring-green-300 transition-all duration-300 transform hover:scale-105 ${fullWidth ? 'w-full' : ''} ${props.disabled ? 'bg-gray-400 cursor-not-allowed' : ''}`}>
      {children}
    </button>
  );
};

interface InputFieldProps extends React.InputHTMLAttributes<HTMLInputElement> {
  label: string;
}

const InputField: FC<InputFieldProps> = ({ label, ...props }) => {
  // Inspired by v2 Form UX: clear labels, clean design
  return (
    <div className="w-full">
      <label className="block text-sm font-medium text-gray-700 mb-1">{label}</label>
      <input
        {...props}
        className="w-full px-4 py-3 text-base border border-gray-300 rounded-md shadow-sm focus:ring-blue-500 focus:border-blue-500" />
    </div>
  );
};

const TrustBadge: FC<PropsWithChildren<{ text: string }>> = ({ children, text }) => {
  return (
    <div className="flex items-center gap-2 text-gray-600">
      {children}
      <span className="text-sm font-medium">{text}</span>
    </div>
  );
};

interface ProgressBarProps {
  steps: string[];
  currentStep: number;
}

const ProgressBar: FC<ProgressBarProps> = ({ steps, currentStep }) => {
  // Inspired by v3.e Progress Indicator
  return (
    <div className="w-full px-4 sm:px-0">
      <div className="flex items-center">
        {steps.map((step, index) => {
          const stepIndex = index + 1;
          const isCompleted = currentStep > stepIndex;
          const isActive = currentStep === stepIndex;
          return (
            <React.Fragment key={step}>
              <div className="flex flex-col items-center">
                <div
                  className={`flex items-center justify-center w-8 h-8 sm:w-10 sm:h-10 rounded-full transition-all duration-300 ${isCompleted ? 'bg-green-500' : isActive ? 'bg-blue-500' : 'bg-gray-300'}`}>
                  {isCompleted ? <CheckIcon /> : <span className={`font-bold ${isActive ? 'text-white' : 'text-gray-600'}`}>{stepIndex}</span>}
                </div>
                <p className={`mt-2 text-xs text-center font-medium ${isActive ? 'text-blue-600' : 'text-gray-500'}`}>{step}</p>
              </div>
              {index < steps.length - 1 && (
                <div className={`flex-auto border-t-2 transition-all duration-300 ${isCompleted ? 'border-green-500' : 'border-gray-300'}`}></div>
              )}
            </React.Fragment>
          );
        })}
      </div>
    </div>
  );
};

// --- STEP COMPONENTS ---

interface StepProps {
  formData: FormData;
  setFormData: React.Dispatch<React.SetStateAction<FormData>>;
}

const Step1_Addresses: FC<StepProps> = ({ formData, setFormData }) => {
  return (
    <div className="w-full space-y-6">
      <h2 className="text-2xl sm:text-3xl font-bold text-gray-800 text-center">Wohin führt Ihr Umzug?</h2>
      <p className="text-center text-gray-600">Starten Sie hier Ihre kostenlose und unverbindliche Anfrage.</p>
      <InputField
        label="Auszugsort (Adresse, PLZ, Ort)"
        placeholder="z.B. Bahnhofstrasse 1, 8001 Zürich"
        value={formData.addressFrom}
        onChange={(e) => setFormData({ ...formData, addressFrom: e.target.value })}
      />
      <InputField
        label="Einzugsort (Adresse, PLZ, Ort)"
        placeholder="z.B. Rue du Rhône 2, 1204 Genève"
        value={formData.addressTo}
        onChange={(e) => setFormData({ ...formData, addressTo: e.target.value })}
      />
      <p className="text-xs text-center text-gray-500">Tipp: Für genaue Adressen erhalten Sie präzisere Offerten.</p>
    </div>
  );
};

const Step2_Details: FC<StepProps> = ({ formData, setFormData }) => {
  const setEstimateMethod = (method: 'quick' | 'detailed') => {
    setFormData({ ...formData, estimateMethod: method });
  };

  return (
    <div className="w-full space-y-6">
      <h2 className="text-2xl sm:text-3xl font-bold text-gray-800 text-center">Erzählen Sie uns von Ihrem Umzugsgut.</h2>

      {/* Hybrid Inventory Selection */}
      <div className="w-full p-1 bg-gray-200 rounded-lg flex">
        <button onClick={() => setEstimateMethod('quick')} className={`w-1/2 py-2 rounded-md font-semibold transition-all ${formData.estimateMethod === 'quick' ? 'bg-white shadow' : 'text-gray-600'}`}>Schnelle Schätzung</button>
        <button onClick={() => setEstimateMethod('detailed')} className={`w-1/2 py-2 rounded-md font-semibold transition-all ${formData.estimateMethod === 'detailed' ? 'bg-white shadow' : 'text-gray-600'}`}>Detaillierte Liste</button>
      </div>

      {formData.estimateMethod === 'quick' ? (
        <div className="space-y-4 text-center p-4 bg-blue-50 rounded-lg">
            <label className="block text-lg font-medium text-gray-800">Wie gross ist Ihre Wohnung?</label>
            <p className='text-sm text-gray-600 mb-4'>Für Effizienz-Maximierer: In 5 Sekunden zum Richtwert.</p>
            <select 
              value={formData.roomCount}
              onChange={e => setFormData({...formData, roomCount: Number(e.target.value)})}
              className="w-full max-w-sm mx-auto px-4 py-3 text-base border border-gray-300 rounded-md shadow-sm focus:ring-blue-500 focus:border-blue-500"
            >
              {[1, 1.5, 2, 2.5, 3, 3.5, 4, 4.5, 5, 5.5, 6].map(r => <option key={r} value={r}>{r} Zimmer</option>)}
              <option value={7}>Grösser als 6 Zimmer</option>
            </select>
        </div>
      ) : (
        <div className="text-center p-4 bg-yellow-50 rounded-lg">
          <p className="font-semibold text-gray-800">Detaillierte Inventarliste</p>
          <p className="text-sm text-gray-600">Für Sicherheits-Sucher: Je genauer die Liste, desto präziser die Fixpreis-Offerte.</p>
          <p className="mt-4 p-4 bg-gray-100 rounded-md">[Hier würde eine detaillierte Inventarlisten-Komponente geladen, z.B. mit Kategorien wie 'Wohnzimmer', 'Küche' und Items wie 'Sofa', 'Tisch', etc.]</p>
        </div>
      )}
    </div>
  );
};

const Step3_Services: FC<StepProps> = ({ formData, setFormData }) => {
  return (
    <div className="w-full space-y-6">
      <h2 className="text-2xl sm:text-3xl font-bold text-gray-800 text-center">Wann und wie möchten Sie umziehen?</h2>

      <div className="space-y-4">
        <InputField
          label="Wunschdatum für den Umzug"
          type="date"
          value={formData.moveDate}
          onChange={(e) => setFormData({ ...formData, moveDate: e.target.value })}
        />
        <div className="flex items-center justify-center">
            <input type="checkbox" id="flexibleDate" checked={formData.dateIsFlexible} onChange={e => setFormData({...formData, dateIsFlexible: e.target.checked})} className="h-4 w-4 text-blue-600 border-gray-300 rounded focus:ring-blue-500" />
            <label htmlFor="flexibleDate" className="ml-2 block text-sm text-gray-900">Datum ist flexibel (+/- 1 Woche <span className='font-semibold text-green-600'>für besseren Preis</span>)</label>
        </div>
      </div>

      <div className="space-y-4 pt-4 border-t">
        <h3 className="text-lg font-semibold text-gray-800 text-center">Benötigen Sie Zusatzleistungen?</h3>
        <p className='text-center text-sm text-gray-600'>Für Chaos-Manager: Geben Sie alle Sorgen ab.</p>
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
            {[ 
                { id: 'packing', label: 'Möbel De-/Montage', guarantee: false },
                { id: 'cleaning', label: 'Endreinigung mit Abnahmegarantie', guarantee: true },
                { id: 'storage', label: 'Möbellagerung', guarantee: false },
            ].map(service => (
                <label key={service.id} htmlFor={service.id} className={`p-4 border rounded-lg cursor-pointer transition-all ${formData.services[service.id as keyof typeof formData.services] ? 'bg-blue-100 border-blue-500 ring-2 ring-blue-500' : 'bg-white border-gray-300'}`}>
                    <input type="checkbox" id={service.id} checked={formData.services[service.id as keyof typeof formData.services]} onChange={e => setFormData({...formData, services: {...formData.services, [service.id]: e.target.checked}})} className="hidden" />
                    <p className="font-bold text-gray-800">{service.label}</p>
                    {service.guarantee && <p className="text-sm font-semibold text-green-600">Sorgenfrei dank Garantie!</p>}
                </label>
            ))}
        </div>
      </div>
    </div>
  );
};

const Step4_Contact: FC<StepProps> = ({ formData, setFormData }) => {
  return (
    <div className="w-full space-y-6">
      <h2 className="text-2xl sm:text-3xl font-bold text-gray-800 text-center">Fast geschafft!</h2>
      <p className="text-center text-gray-600">Wohin dürfen wir Ihre <span className='font-bold'>kostenlosen Offerten</span> senden?</p>

      <div className="space-y-4">
        <InputField
          label="Vollständiger Name"
          placeholder="Max Mustermann"
          value={formData.contact.name}
          onChange={(e) => setFormData({ ...formData, contact: {...formData.contact, name: e.target.value} })}
        />
        <InputField
          label="E-Mail Adresse"
          type="email"
          placeholder="max.mustermann@email.ch"
          value={formData.contact.email}
          onChange={(e) => setFormData({ ...formData, contact: {...formData.contact, email: e.target.value} })}
        />
        <InputField
          label="Telefonnummer (für Rückfragen)"
          type="tel"
          placeholder="079 123 45 67"
          value={formData.contact.phone}
          onChange={(e) => setFormData({ ...formData, contact: {...formData.contact, phone: e.target.value} })}
        />
      </div>
      <div className='p-4 bg-gray-100 rounded-lg text-sm text-gray-700 space-y-2'>
        <h4 className='font-bold'>Ihre Anfrage im Überblick:</h4>
        <p><strong>Von:</strong> {formData.addressFrom || 'N/A'}</p>
        <p><strong>Nach:</strong> {formData.addressTo || 'N/A'}</p>
        <p><strong>Umfang:</strong> {formData.estimateMethod === 'quick' ? `${formData.roomCount} Zimmer` : 'Detaillierte Liste'}</p>
      </div>
    </div>
  );
};

const ConfirmationScreen: FC = () => {
  return (
    <div className="w-full text-center space-y-4 py-10">
        <div className='mx-auto w-20 h-20 flex items-center justify-center bg-green-500 rounded-full'>
            <SvgIcon svg='<svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke-width="2" stroke="white" class="w-12 h-12"><path stroke-linecap="round" stroke-linejoin="round" d="M4.5 12.75l6 6 9-13.5" /></svg>' />
        </div>
        <h2 className="text-2xl sm:text-3xl font-bold text-gray-800">Vielen Dank! Ihre Anfrage wurde übermittelt.</h2>
        <div className='text-left max-w-md mx-auto p-6 bg-gray-50 rounded-lg border border-gray-200'>
            <h3 className='font-bold text-lg mb-2'>Was passiert als Nächstes?</h3>
            <ul className='space-y-2 list-decimal list-inside text-gray-700'>
                <li>Wir leiten Ihre Anfrage an bis zu 5 geprüfte Umzugsfirmen aus Ihrer Region weiter.</li>
                <li>Die Firmen werden sich in Kürze mit massgeschneiderten Offerten bei Ihnen melden.</li>
                <li>Sie vergleichen in Ruhe und wählen das beste Angebot aus. Für Sie ist dieser Service 100% kostenlos.</li>
            </ul>
        </div>
        <p className="text-sm text-gray-500 pt-4">Sie erhalten in wenigen Minuten eine Bestätigung per E-Mail.</p>
    </div>
  )
}

// --- THE ULTIMATE FLOW COMPONENT ---

export const UltimateSwissFlow: FC = () => {
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState<FormData>({
    addressFrom: '',
    addressTo: '',
    estimateMethod: 'quick',
    roomCount: 2.5,
    inventory: [],
    floorFrom: '1',
    floorTo: '2',
    liftFrom: false,
    liftTo: false,
    moveDate: new Date().toISOString().split('T')[0],
    dateIsFlexible: false,
    services: { packing: false, cleaning: false, storage: false },
    contact: { name: '', email: '', phone: '' },
  });

  const steps = ["Adressen", "Umfang", "Services", "Kontakt"];

  const nextStep = () => setCurrentStep(prev => Math.min(prev + 1, steps.length + 1));
  const prevStep = () => setCurrentStep(prev => Math.max(prev - 1, 1));

  const handleSubmit = (e: React.FormEvent) => {
      e.preventDefault();
      console.log("Submitting Form Data:", formData);
      // API call would go here
      nextStep(); // Move to confirmation screen
  }

  const isStepValid = () => {
    switch(currentStep) {
        case 1: return formData.addressFrom.length > 3 && formData.addressTo.length > 3;
        case 4: return formData.contact.name.length > 1 && formData.contact.email.includes('@') && formData.contact.phone.length > 5;
        default: return true;
    }
  }

  return (
    <div className="bg-gray-50 min-h-screen font-sans flex flex-col items-center py-6 sm:py-12">
      <div className="w-full max-w-3xl mx-auto bg-white rounded-xl shadow-2xl overflow-hidden">
        <div className="p-6 sm:p-8 space-y-8">
          {/* Header & Progress Bar (from v3.e) */}
          <div className='flex justify-center mb-6'>
             <ProgressBar steps={steps} currentStep={currentStep} />
          </div>

          {/* Main Content Area */}
          <div className="min-h-[350px] flex items-center">
            {currentStep === 1 && <Step1_Addresses formData={formData} setFormData={setFormData} />}
            {currentStep === 2 && <Step2_Details formData={formData} setFormData={setFormData} />}
            {currentStep === 3 && <Step3_Services formData={formData} setFormData={setFormData} />}
            {currentStep === 4 && <Step4_Contact formData={formData} setFormData={setFormData} />}
            {currentStep > steps.length && <ConfirmationScreen />}
          </div>
        </div>

        {/* Footer & Navigation - includes Sticky CTA (Quick Win) & Trust Badges (v2e) */}
        {currentStep <= steps.length && (
            <footer className="sticky bottom-0 bg-white/80 backdrop-blur-sm border-t border-gray-200 p-4">
                <div className='max-w-3xl mx-auto'>
                    <div className='flex items-center justify-between gap-4'>
                        {currentStep > 1 
                            ? <button onClick={prevStep} className='flex items-center gap-2 font-semibold text-gray-600 hover:text-gray-900 p-2'><ArrowLeftIcon/> Zurück</button>
                            : <div className='hidden sm:flex items-center gap-4'>
                                <TrustBadge text="Geprüfte Firmen"><SwissFlagIcon/></TrustBadge>
                                <TrustBadge text="ASTAG Partner"><AstagIcon/></TrustBadge>
                              </div>
                        }

                        {currentStep < steps.length ? (
                            <PrimaryButton onClick={nextStep} disabled={!isStepValid()}>
                                Weiter <ArrowRightIcon />
                            </PrimaryButton>
                        ) : (
                            <form onSubmit={handleSubmit} className='w-full sm:w-auto'>
                                <PrimaryButton type='submit' fullWidth={true} disabled={!isStepValid()}>
                                    Jetzt Offerten erhalten
                                </PrimaryButton>
                            </form>
                        )}
                    </div>
                    {currentStep === steps.length && (
                        <div className='mt-3 text-center text-xs text-gray-500 space-y-1'>
                            <p>Mit Klick auf "Jetzt Offerten erhalten" stimmen Sie unseren AGB und Datenschutzbestimmungen zu.</p>
                            <p className='font-semibold'>100% kostenlos & unverbindlich.</p>
                        </div>
                    )}
                </div>
            </footer>
        )}
      </div>
    </div>
  );
};

