// --- TYPE DEFINITIONS ---
type FormData = {
  addressFrom: string;
  addressTo: string;
  roomCount: number;
  floorFrom: number;
  floorTo: number;
  liftFrom: boolean;
  liftTo: boolean;
  packingService: boolean;
  cleaningService: boolean;
  moveDate: string;
  fullName: string;
  email: string;
  phone: string;
};

const initialFormData: FormData = {
  addressFrom: '',
  addressTo: '',
  roomCount: 2.5,
  floorFrom: 1,
  floorTo: 2,
  liftFrom: false,
  liftTo: true,
  packingService: false,
  cleaningService: false,
  moveDate: '',
  fullName: '',
  email: '',
  phone: '',
};

// --- SHARED COMPONENTS (aus Implementierungsgründen hier inline) ---

const TrustBadges: FC = () => (
  <div style={{ display: 'flex', gap: '16px', alignItems: 'center', justifyContent: 'center', flexWrap: 'wrap', padding: '8px 0' }}>
    <span style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>🇨🇭 Schweizer Firma</span>
    <span style={{ fontWeight: 'bold' }}>✓ ASTAG Mitglied</span>
    <span style={{ fontWeight: 'bold' }}>✓ Fixpreis-Garantie</span>
    <span>⭐ 4.9/5.0 (Google)</span>
  </div>
);

const ProgressIndicator: FC<{ currentStep: number; totalSteps: number }> = ({ currentStep, totalSteps }) => (
  <div style={{ position: 'sticky', top: 0, zIndex: 10, backgroundColor: '#f0f0f0' }}>
    <div style={{ width: `${(currentStep / totalSteps) * 100}%`, height: '8px', backgroundColor: '#007aff', transition: 'width 0.3s ease' }} />
  </div>
);

const StepWrapper: FC<PropsWithChildren<{ title: string; description: string }>> = ({ title, description, children }) => (
  <div style={{ padding: '24px', maxWidth: '600px', margin: '0 auto' }}>
    <h2 style={{ fontSize: '24px', fontWeight: 'bold', margin: 0 }}>{title}</h2>
    <p style={{ color: '#666', marginTop: '8px', marginBottom: '24px' }}>{description}</p>
    <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
      {children}
    </div>
  </div>
);

const InputField: FC<React.InputHTMLAttributes<HTMLInputElement> & { label: string }> = ({ label, ...props }) => (
    <div>
        <label style={{ display: 'block', marginBottom: '4px', fontWeight: '500' }}>{label}</label>
        <input {...props} style={{ width: '100%', padding: '12px', fontSize: '16px', borderRadius: '8px', border: '1px solid #ccc' }} />
    </div>
);

const StickyFooter: FC<PropsWithChildren> = ({ children }) => (
    <div style={{ position: 'sticky', bottom: 0, backgroundColor: 'white', padding: '16px', borderTop: '1px solid #e0e0e0', boxShadow: '0 -2px 10px rgba(0,0,0,0.05)' }}>
        <div style={{ maxWidth: '600px', margin: '0 auto', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            {children}
        </div>
    </div>
);

const PrimaryButton: FC<React.ButtonHTMLAttributes<HTMLButtonElement>> = (props) => (
    <button {...props} style={{ backgroundColor: '#007aff', color: 'white', border: 'none', padding: '14px 24px', fontSize: '16px', fontWeight: 'bold', borderRadius: '8px', cursor: 'pointer', width: '100%' }} />
);

const SecondaryButton: FC<React.ButtonHTMLAttributes<HTMLButtonElement>> = (props) => (
    <button {...props} style={{ backgroundColor: 'transparent', color: '#007aff', border: 'none', padding: '14px 24px', fontSize: '16px', cursor: 'pointer' }} />
);

// --- STEP COMPONENTS ---

const Step1: FC<{ data: FormData; update: (d: Partial<FormData>) => void }> = ({ data, update }) => (
  <StepWrapper title="Wohin ziehen Sie?" description="Starten Sie hier Ihre unverbindliche Offertenanfrage.">
    <InputField label="Auszugsadresse" placeholder="z.B. Musterstrasse 1, 8001 Zürich" value={data.addressFrom} onChange={e => update({ addressFrom: e.target.value })} />
    <InputField label="Einzugsadresse" placeholder="z.B. Beispielweg 2, 3001 Bern" value={data.addressTo} onChange={e => update({ addressTo: e.target.value })} />
  </StepWrapper>
);

const Step2: FC<{ data: FormData; update: (d: Partial<FormData>) => void }> = ({ data, update }) => (
  <StepWrapper title="Details zu Ihrer Wohnung" description="Diese Angaben helfen uns, den Aufwand genau einzuschätzen.">
    <InputField label="Anzahl Zimmer" type="number" step="0.5" value={data.roomCount} onChange={e => update({ roomCount: parseFloat(e.target.value) })} />
    <InputField label="Stockwerk (Auszug)" type="number" value={data.floorFrom} onChange={e => update({ floorFrom: parseInt(e.target.value) })} />
    <InputField label="Stockwerk (Einzug)" type="number" value={data.floorTo} onChange={e => update({ floorTo: parseInt(e.target.value) })} />
    <div style={{ display: 'flex', justifyContent: 'space-between' }}>
      <label><input type="checkbox" checked={data.liftFrom} onChange={e => update({ liftFrom: e.target.checked })} /> Lift am Auszugsort</label>
      <label><input type="checkbox" checked={data.liftTo} onChange={e => update({ liftTo: e.target.checked })} /> Lift am Einzugsort</label>
    </div>
  </StepWrapper>
);

const Step3: FC<{ data: FormData; update: (d: Partial<FormData>) => void }> = ({ data, update }) => (
  <StepWrapper title="Benötigen Sie Zusatzleistungen?" description="Alles aus einer Hand für einen stressfreien Umzug.">
    <label style={{ padding: '12px', border: '1px solid #ccc', borderRadius: '8px' }}><input type="checkbox" checked={data.packingService} onChange={e => update({ packingService: e.target.checked })} /> Ja, ich benötige Ein- / Auspackservice</label>
    <label style={{ padding: '12px', border: '1px solid #ccc', borderRadius: '8px' }}><input type="checkbox" checked={data.cleaningService} onChange={e => update({ cleaningService: e.target.checked })} /> Ja, ich wünsche eine Umzugsreinigung mit Abnahmegarantie</label>
  </StepWrapper>
);

const Step4: FC<{ data: FormData; update: (d: Partial<FormData>) => void }> = ({ data, update }) => (
  <StepWrapper title="Fast geschafft!" description="Wir senden Ihnen in Kürze Ihr persönliches Fixpreis-Angebot zu.">
    <InputField label="Wunschtermin" type="date" value={data.moveDate} onChange={e => update({ moveDate: e.target.value })} />
    <InputField label="Vollständiger Name" placeholder="Max Muster" value={data.fullName} onChange={e => update({ fullName: e.target.value })} />
    <InputField label="E-Mail" type="email" placeholder="max.muster@email.ch" value={data.email} onChange={e => update({ email: e.target.value })} />
    <InputField label="Telefon (für Rückfragen)" type="tel" placeholder="079 123 45 67" value={data.phone} onChange={e => update({ phone: e.target.value })} />
    <p style={{fontSize: '12px', color: '#888'}}>Ihre Daten sind sicher und werden nur zur Angebotserstellung verwendet.</p>
  </StepWrapper>
);


// --- MAIN ULTIMATE FLOW COMPONENT ---

const UltimateSwissFlow: FC = () => {
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState<FormData>(initialFormData);
  const totalSteps = 4;

  const updateFormData = (newData: Partial<FormData>) => {
    setFormData(prev => ({ ...prev, ...newData }));
  };

  const handleNext = () => {
    if (currentStep < totalSteps) {
      setCurrentStep(currentStep + 1);
    }
  };

  const handlePrev = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
      e.preventDefault();
      console.log("Form Submitted:", formData);
      alert("Vielen Dank! Ihr Angebot wird erstellt und Ihnen per E-Mail zugesendet.");
  };

  const renderStep = () => {
    switch (currentStep) {
      case 1: return <Step1 data={formData} update={updateFormData} />;
      case 2: return <Step2 data={formData} update={updateFormData} />;
      case 3: return <Step3 data={formData} update={updateFormData} />;
      case 4: return <Step4 data={formData} update={updateFormData} />;
      default: return <Step1 data={formData} update={updateFormData} />;
    }
  };

  return (
    <div style={{ fontFamily: 'sans-serif', backgroundColor: '#fff' }}>
      <ProgressIndicator currentStep={currentStep} totalSteps={totalSteps} />
      <header style={{ padding: '16px' }}>
        <h1 style={{ textAlign: 'center', fontSize: '28px', margin: '0 0 16px 0' }}>Umzugsofferte berechnen</h1>
        <TrustBadges />
      </header>
      <main>
        <form onSubmit={handleSubmit}>
            {renderStep()}
            <StickyFooter>
                {currentStep > 1 ? (
                    <SecondaryButton type="button" onClick={handlePrev}>Zurück</SecondaryButton>
                ) : <div/> /* Placeholder to keep alignment */}

                {currentStep < totalSteps ? (
                    <PrimaryButton type="button" onClick={handleNext}>Weiter</PrimaryButton>
                ) : (
                    <PrimaryButton type="submit">Fixpreis-Angebot erhalten</PrimaryButton>
                )}
            </StickyFooter>
        </form>
      </main>
    </div>
  );
};

export default UltimateSwissFlow;

