import React, { useState, useMemo } from 'react';

// --- TYPE DEFINITIONS ---
type FormData = {
  fromAddress: string;
  toAddress: string;
  moveDate: string;
  roomCount: number | null;
  floor: number | null;
  hasElevator: boolean | null;
  inventoryType: 'quick' | 'detailed' | null;
  inventoryItems: { [key: string]: number };
  services: {
    cleaning: boolean;
    packing: boolean;
    assembly: boolean;
  };
  contact: {
    name: string;
    email: string;
    phone: string;
  };
};

// --- STYLING (CSS-in-JS Object) ---
// In a real app, this would be in a separate file or using a library like styled-components
const styles: { [key: string]: React.CSSProperties } = {
  container: {
    fontFamily: '"Helvetica Neue", Helvetica, Arial, sans-serif',
    backgroundColor: '#f4f6f8',
    maxWidth: '700px',
    margin: '0 auto',
    border: '1px solid #e0e0e0',
    borderRadius: '12px',
    overflow: 'hidden',
    boxShadow: '0 8px 32px rgba(0,0,0,0.1)',
  },
  header: {
    padding: '16px 24px',
    backgroundColor: '#ffffff',
    borderBottom: '1px solid #e0e0e0',
  },
  headerTitle: {
    fontSize: '20px',
    fontWeight: 700,
    color: '#1A2B4D',
    margin: 0,
  },
  content: {
    padding: '24px',
    minHeight: '400px',
  },
  stickyFooter: {
    position: 'sticky',
    bottom: 0,
    left: 0,
    right: 0,
    backgroundColor: '#ffffff',
    padding: '16px 24px',
    borderTop: '1px solid #e0e0e0',
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    boxShadow: '0 -4px 16px rgba(0,0,0,0.05)',
  },
  button: {
    padding: '14px 28px',
    border: 'none',
    borderRadius: '8px',
    fontSize: '16px',
    fontWeight: 600,
    cursor: 'pointer',
    transition: 'all 0.2s ease-in-out',
  },
  buttonPrimary: {
    backgroundColor: '#007aff', // Primary CTA from v5
    color: 'white',
  },
  buttonSecondary: {
    backgroundColor: '#e0e0e0',
    color: '#333',
  },
};

// --- SHARED COMPONENTS ---
// These would typically be in their own files, e.g., 'src/components/calculator-variants/shared/ProgressIndicator.tsx'

const ProgressIndicator: React.FC<{ currentStep: number; totalSteps: number; steps: string[] }> = ({ currentStep, totalSteps, steps }) => (
  <div style={{ padding: '20px 24px', backgroundColor: '#fff', borderBottom: '1px solid #e0e0e0' }}>
    <p style={{ margin: '0 0 10px 0', fontSize: '14px', color: '#555' }}>Schritt {currentStep} von {totalSteps}</p>
    <div style={{ display: 'flex', gap: '4px' }}>
      {Array.from({ length: totalSteps }).map((_, index) => (
        <div key={index} style={{
          flex: 1,
          height: '6px',
          borderRadius: '3px',
          backgroundColor: index < currentStep ? '#007aff' : '#e0e0e0',
          transition: 'background-color 0.3s ease',
        }}></div>
      ))}
    </div>
  </div>
);

const TrustBadges: React.FC<{ placement: 'footer' | 'final' }> = ({ placement }) => {
    const style: React.CSSProperties = placement === 'footer' ? { display: 'flex', gap: '8px', alignItems: 'center' } : { textAlign: 'center', marginTop: '16px' };
    const text = placement === 'footer' ? null : <p style={{fontSize: '12px', color: '#666', margin: '8px 0 0 0'}}>100% Sicher & Unverbindlich</p>
    return (
        <div style={style}>
            <span title="ASTAG Partner">🇨🇭</span>
            <span title="Bewertungen">⭐ 4.8/5</span>
            <span title="Preisgarantie">🛡️</span>
            {text}
        </div>
    );
};

const FormField: React.FC<{ label: string; type: string; value: string; onChange: (e: React.ChangeEvent<HTMLInputElement>) => void; placeholder?: string }> = ({ label, ...props }) => (
  <div style={{ marginBottom: '20px' }}>
    <label style={{ display: 'block', fontWeight: 500, marginBottom: '8px', color: '#1A2B4D' }}>{label}</label>
    <input {...props} style={{ width: '100%', padding: '12px', fontSize: '16px', border: '1px solid #ccc', borderRadius: '8px' }} />
  </div>
);

const IconCardSelect: React.FC<{ icon: string; label: string; isSelected: boolean; onClick: () => void; }> = ({ icon, label, isSelected, onClick }) => (
    <button onClick={onClick} style={{
        display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
        padding: '16px', border: isSelected ? '2px solid #007aff' : '2px solid #e0e0e0',
        borderRadius: '12px', cursor: 'pointer', backgroundColor: isSelected ? '#f0f8ff' : '#fff',
        textAlign: 'center', flex: 1, minWidth: '100px', transition: 'all 0.2s ease'
    }}>
        <span style={{ fontSize: '32px' }}>{icon}</span>
        <span style={{ marginTop: '8px', fontWeight: 500 }}>{label}</span>
    </button>
);

// --- STEP COMPONENTS ---

const Step1_Logistics: React.FC<{ data: FormData; updateData: (d: Partial<FormData>) => void; }> = ({ data, updateData }) => (
    <div>
        <h2 style={styles.headerTitle}>Wohin geht die Reise?</h2>
        <p style={{color: '#555', marginTop: 0}}>Starten Sie hier Ihre unverbindliche Anfrage.</p>
        <FormField label="Auszugsort" type="text" value={data.fromAddress} onChange={e => updateData({ fromAddress: e.target.value })} placeholder="z.B. Bahnhofstrasse 1, 8001 Zürich" />
        <FormField label="Einzugsort" type="text" value={data.toAddress} onChange={e => updateData({ toAddress: e.target.value })} placeholder="z.B. Hauptgasse 5, 3001 Bern" />
        <FormField label="Gewünschtes Umzugsdatum" type="date" value={data.moveDate} onChange={e => updateData({ moveDate: e.target.value })} />
    </div>
);

const Step2_Details: React.FC<{ data: FormData; updateData: (d: Partial<FormData>) => void; }> = ({ data, updateData }) => (
    <div>
        <h2 style={styles.headerTitle}>Erzählen Sie uns von Ihrer Wohnung</h2>
        <div style={{ marginBottom: '24px' }}>
            <p style={{ fontWeight: 500, color: '#1A2B4D' }}>Anzahl Zimmer</p>
            <div style={{ display: 'flex', gap: '10px' }}>
                {[1, 2, 3, 4, 5].map(n => <IconCardSelect key={n} icon={`${n}.5`} label={` ${n}.5 Zimmer `} isSelected={data.roomCount === n} onClick={() => updateData({ roomCount: n })} />)}
            </div>
        </div>
        <div style={{ marginBottom: '24px' }}>
            <p style={{ fontWeight: 500, color: '#1A2B4D' }}>Stockwerk (Auszug)</p>
            <div style={{ display: 'flex', gap: '10px' }}>
                {[0, 1, 2, 3, 4].map(n => <IconCardSelect key={n} icon={'🏢'} label={n === 0 ? 'EG' : `${n}. Stock`} isSelected={data.floor === n} onClick={() => updateData({ floor: n })} />)}
            </div>
        </div>
        <div>
            <p style={{ fontWeight: 500, color: '#1A2B4D' }}>Lift vorhanden?</p>
            <div style={{ display: 'flex', gap: '10px' }}>
                <IconCardSelect icon="✅" label="Ja" isSelected={data.hasElevator === true} onClick={() => updateData({ hasElevator: true })} />
                <IconCardSelect icon="❌" label="Nein" isSelected={data.hasElevator === false} onClick={() => updateData({ hasElevator: false })} />
            </div>
        </div>
    </div>
);

const Step3_Inventory: React.FC<{ data: FormData; updateData: (d: Partial<FormData>) => void; }> = ({ data, updateData }) => (
    <div>
        <h2 style={styles.headerTitle}>Was wird gezügelt?</h2>
        <p style={{color: '#555', marginTop: 0}}>Wählen Sie für eine genaue Offerte.</p>
        <div style={{ display: 'flex', gap: '10px', marginBottom: '24px' }}>
            <IconCardSelect icon="🚀" label="Schnell-Schätzung" isSelected={data.inventoryType === 'quick'} onClick={() => updateData({ inventoryType: 'quick' })} />
            <IconCardSelect icon="📋" label="Detaillierte Liste" isSelected={data.inventoryType === 'detailed'} onClick={() => updateData({ inventoryType: 'detailed' })} />
        </div>
        {data.inventoryType === 'quick' && <p style={{backgroundColor: '#eef', padding: '15px', borderRadius: '8px'}}>Basierend auf {data.roomCount || 'Ihrer'} Zimmer Wohnung schätzen wir das Volumen. Sie erhalten Offerten basierend auf dieser Schätzung.</p>}
        {data.inventoryType === 'detailed' && <p style={{backgroundColor: '#eef', padding: '15px', borderRadius: '8px'}}>Eine detaillierte Inventarliste wird hier angezeigt. Aus Komplexitätsgründen ist diese im Code-Beispiel nicht implementiert.</p>}
    </div>
);

const Step4_Services: React.FC<{ data: FormData; updateData: (d: Partial<FormData>) => void; }> = ({ data, updateData }) => (
    <div>
        <h2 style={styles.headerTitle}>Benötigen Sie weitere Hilfe?</h2>
        <p style={{color: '#555', marginTop: 0}}>Wählen Sie optionale Zusatzleistungen.</p>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
             <IconCardSelect icon="✨" label="Reinigung mit Abnahmegarantie" isSelected={data.services.cleaning} onClick={() => updateData({ services: { ...data.services, cleaning: !data.services.cleaning } })} />
             <IconCardSelect icon="📦" label="Verpackungsmaterial & Hilfe" isSelected={data.services.packing} onClick={() => updateData({ services: { ...data.services, packing: !data.services.packing } })} />
             <IconCardSelect icon="🛠️" label="Möbel De- & Montage" isSelected={data.services.assembly} onClick={() => updateData({ services: { ...data.services, assembly: !data.services.assembly } })} />
        </div>
    </div>
);

const Step5_Contact: React.FC<{ data: FormData; updateData: (d: Partial<FormData>) => void; summary: React.ReactNode }> = ({ data, updateData, summary }) => (
    <div style={{ display: 'flex', gap: '24px' }}>
        <div style={{flex: 1}}>
            <h2 style={styles.headerTitle}>Fast geschafft!</h2>
            <p style={{color: '#555', marginTop: 0}}>Wohin dürfen wir Ihre Offerten senden?</p>
            <FormField label="Vollständiger Name" type="text" value={data.contact.name} onChange={e => updateData({ contact: {...data.contact, name: e.target.value} })} />
            <FormField label="E-Mail" type="email" value={data.contact.email} onChange={e => updateData({ contact: {...data.contact, email: e.target.value} })} />
            <FormField label="Telefon (für Rückfragen)" type="tel" value={data.contact.phone} onChange={e => updateData({ contact: {...data.contact, phone: e.target.value} })} />
            <TrustBadges placement="final" />
        </div>
        <div style={{flex: 1, backgroundColor: '#f4f6f8', padding: '20px', borderRadius: '12px', border: '1px solid #e0e0e0'}}>
           <h3 style={{marginTop: 0, color: '#1A2B4D'}}>Ihre Anfrage</h3>
           {summary}
        </div>
    </div>
);

// --- MAIN FLOW COMPONENT ---

export const UltimateSwissFlow: React.FC = () => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<FormData>({
    fromAddress: '', toAddress: '', moveDate: '',
    roomCount: null, floor: null, hasElevator: null,
    inventoryType: null, inventoryItems: {},
    services: { cleaning: false, packing: false, assembly: false },
    contact: { name: '', email: '', phone: '' },
  });

  const updateFormData = (newData: Partial<FormData>) => {
    setFormData(prev => ({ ...prev, ...newData }));
  };

  const totalSteps = 5;
  const stepNames = ["Logistik", "Details", "Inventar", "Services", "Abschluss"];

  const nextStep = () => setStep(s => Math.min(s + 1, totalSteps));
  const prevStep = () => setStep(s => Math.max(s - 1, 1));

  const handleSubmit = () => {
      alert('Anfrage gesendet! Formulardaten:\n' + JSON.stringify(formData, null, 2));
  };

  const summary = useMemo(() => (
    <ul style={{listStyle: 'none', padding: 0, fontSize: '14px', color: '#333'}}>
        <li><strong>Von:</strong> {formData.fromAddress || '-'}</li>
        <li><strong>Nach:</strong> {formData.toAddress || '-'}</li>
        <li><strong>Datum:</strong> {formData.moveDate || '-'}</li>
        <li><strong>Zimmer:</strong> {formData.roomCount ? `${formData.roomCount}.5` : '-'}</li>
        <li><strong>Services:</strong> {Object.entries(formData.services).filter(([_, v]) => v).map(([k]) => k).join(', ') || 'Keine'}</li>
    </ul>
  ), [formData]);

  const renderStep = () => {
    switch (step) {
      case 1: return <Step1_Logistics data={formData} updateData={updateFormData} />;
      case 2: return <Step2_Details data={formData} updateData={updateFormData} />;
      case 3: return <Step3_Inventory data={formData} updateData={updateFormData} />;
      case 4: return <Step4_Services data={formData} updateData={updateFormData} />;
      case 5: return <Step5_Contact data={formData} updateData={updateFormData} summary={summary} />;
      default: return <div>Unbekannter Schritt</div>;
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <h1 style={styles.headerTitle}>Umzugsofferten Schweiz</h1>
      </div>
      <ProgressIndicator currentStep={step} totalSteps={totalSteps} steps={stepNames} />
      <div style={styles.content}>
        {renderStep()}
      </div>
      <div style={styles.stickyFooter}>
        {step > 1 ? (
          <button onClick={prevStep} style={{...styles.button, ...styles.buttonSecondary}}>Zurück</button>
        ) : <div/> /* Placeholder to keep CTA on the right */}
        <TrustBadges placement="footer" />
        {step < totalSteps ? (
          <button onClick={nextStep} style={{...styles.button, ...styles.buttonPrimary}}>Weiter</button>
        ) : (
          <button onClick={handleSubmit} style={{...styles.button, ...styles.buttonPrimary}}>Kostenlose Offerten anfordern</button>
        )}
      </div>
    </div>
  );
};

