import React, { useState, useMemo } from 'react';

// Annahme: Es existiert eine Styling-Lösung wie styled-components oder TailwindCSS.
// Die Styles hier sind als Inline-Objekte zur Veranschaulichung.

// --- TYPE DEFINITIONS ---
type FormData = {
