// --- ICONS (Placeholder) ---
const TrustIconASTAG = () => <div style={{ border: '1px solid #ccc', padding: '2px 5px', fontSize: '10px', borderRadius: '4px' }}>ASTAG</div>;
const TrustIconGoogle = () => <div style={{ border: '1px solid #ccc', padding: '2px 5px', fontSize: '10px', borderRadius: '4px' }}>★★★★★ Google</div>;
const ArrowRightIcon = () => <span>→</span>;

// --- SHARED COMPONENTS (simuliert) ---
const ProgressIndicator = ({ currentStep, totalSteps, steps }: { currentStep: number; totalSteps: number, steps: string[] }) => (
  <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '2rem', padding: '0 10px' }}>
    {steps.map((name, index) => (
      <div key={index} style={{ flex: 1, textAlign: 'center' }}>
