        <input type="text" placeholder="Ort" value={data.toAddress.city} onChange={e => setData({...data, toAddress: {...data.toAddress, city: e.target.value}})} style={{ flex: 1, padding: '12px', fontSize: '16px' }} />
      </div>
    </div>
