);

const Step2_Details = ({ data, setData }: any) => (
  <div>
    <h2>Erzählen Sie uns von den Wohnungen.</h2>
    {/* ... Implementierung für Stockwerk, Lift, Zimmer etc. ... */}
    <p>Hier würden visuelle Komponenten für Zimmeranzahl, Stockwerk und Lift-Verfügbarkeit folgen.</p>
  </div>
);

// ... Weitere Step-Komponenten (Step3_Inventory, Step4_Services, etc.) würden hier folgen ...

const Step6_Summary = ({ data, setStep }: any) => (
  <div>
      <h2>Zusammenfassung</h2>
      <p>Bitte prüfen Sie Ihre Angaben, bevor Sie Ihre unverbindlichen Offerten anfordern.</p>
      <div style={{background: '#f8f9fa', padding: '1rem', borderRadius: '8px'}}>
          <p><strong>Von:</strong> {data.fromAddress.plz} {data.fromAddress.city} <a href="#" onClick={() => setStep(1)} style={{fontSize: '12px'}}>Ändern</a></p>
          <p><strong>Nach:</strong> {data.toAddress.plz} {data.toAddress.city} <a href="#" onClick={() => setStep(1)} style={{fontSize: '12px'}}>Ändern</a></p>
          {/* ... weitere Zusammenfassungs-Daten ... */}
      </div>
  </div>
);

// --- MAIN COMPONENT ---
export const UltimateFlowV6 = () => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<FormData>({
    fromAddress: { plz: '', city: '' },
    toAddress: { plz: '', city: '' },
    propertyType: null,
    rooms: 3.5,
    floorFrom: 1,
    floorTo: 2,
    liftFrom: null,
    liftTo: null,
    inventoryMethod: 'estimate',
    services: { packing: false, assembly: false, cleaning: false },
    moveDate: '',
    contact: { name: '', email: '', phone: '' },
  });

  const totalSteps = 6;
  const stepNames = ['Adressen', 'Details', 'Inventar', 'Service', 'Kontakt', 'Abschluss'];

  const handleNext = () => {
    if (step < totalSteps) {
      setStep(step + 1);
    } else {
      // Submit logic
      alert('Formular abgeschickt! Daten: ' + JSON.stringify(formData, null, 2));
    }
  };

  const handleBack = () => {
    if (step > 1) {
      setStep(step - 1);
    }
  };

  // Validierung pro Schritt, um den 'Weiter'-Button zu aktivieren/deaktivieren
  const isStepValid = useMemo(() => {
    switch (step) {
      case 1:
        return formData.fromAddress.plz.length >= 4 && formData.toAddress.plz.length >= 4;
      // ... weitere Validierungsregeln für andere Schritte
      default:
        return true;
    }
  }, [step, formData]);

  const renderStep = () => {
    switch (step) {
      case 1: return <Step1_Addresses data={formData} setData={setFormData} />;
      case 2: return <Step2_Details data={formData} setData={setFormData} />;
      // ... cases für 3, 4, 5
      case 6: return <Step6_Summary data={formData} setStep={setStep} />;
      default: return <Step1_Addresses data={formData} setData={setFormData} />; 
    }
  };

  return (
    <div style={{ fontFamily: 'sans-serif', maxWidth: '700px', margin: '0 auto', padding: '2rem 1rem 8rem 1rem' }}>
      <header style={{ textAlign: 'center', marginBottom: '2rem' }}>
        <h1>Umzugsofferte einholen</h1>
        <p>In 2 Minuten zu 5 kostenlosen & unverbindlichen Offerten von geprüften Umzugsfirmen.</p>
        {/* Prominente Trust-Badges im Header - inspiriert von v5.d */}
        <div style={{ display: 'flex', justifyContent: 'center', gap: '1rem', marginTop: '1rem' }}>
            <TrustIconASTAG />
            <TrustIconGoogle />
            <div>🇨🇭 Schweizer Firmen</div>
        </div>
      </header>

      {/* Progress Indicator - inspiriert von v5a */}
      <ProgressIndicator currentStep={step} totalSteps={totalSteps} steps={stepNames} />

      <main>
        {renderStep()}
      </main>

      {/* Sticky CTA & Trust - Quick Win für alle Flows */}
      <StickyCTA 
        onNext={handleNext}
        onBack={handleBack}
        isFirstStep={step === 1}
        isLastStep={step === totalSteps}
        disabled={!isStepValid}
      />
    </div>
  );
};

