import React, { useState, useMemo } from 'react';
import { ArrowLeft, Check, Home, Truck, Box, Calendar, User, Star, Shield } from 'lucide-react';
import { AnimatePresence, motion } from 'framer-motion';

// Annahme: Diese Shared Components existieren und sind importiert.
// Der Code für sie befindet sich im 'sharedComponents' Array.
import { ProgressIndicator } from './shared/ProgressIndicator';
import { PrimaryButton } from './shared/PrimaryButton';
import { TrustBadges } from './shared/TrustBadges';
import { StepWrapper } from './shared/StepWrapper';
import { InputField } from './shared/InputField';
import { CardSelect } from './shared/CardSelect';

// --- TYPENDATEI: types.ts ---
type MoveDetails = {
  fromAddress: string;
  toAddress: string;
  roomSize: string | null;
  inventory: string;
  services: string[];
  moveDate: string;
  dateIsFlexible: boolean;
  name: string;
  email: string;
  phone: string;
};

const initialData: MoveDetails = {
  fromAddress: '',
  toAddress: '',
  roomSize: null,
  inventory: '',
  services: [],
  moveDate: '',
  dateIsFlexible: false,
  name: '',
  email: '',
  phone: '',
};

const STEPS = [
  { id: 1, name: 'Start & Ziel', icon: Home },
  { id: 2, name: 'Umzugsgut', icon: Box },
  { id: 3, name: 'Services', icon: Truck },
  { id: 4, name: 'Kontakt', icon: User },
  { id: 5, name: 'Absenden', icon: Check },
];

// --- HAUPTKOMPONENTE: UltimateSwissFlow.tsx ---
export const UltimateSwissFlow = () => {
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState<MoveDetails>(initialData);
  const [direction, setDirection] = useState(1);

  const handleNext = () => {
    if (currentStep < STEPS.length) {
      setDirection(1);
      setCurrentStep(prev => prev + 1);
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setDirection(-1);
      setCurrentStep(prev => prev - 1);
    }
  };

  const updateFormData = (newData: Partial<MoveDetails>) => {
    setFormData(prev => ({ ...prev, ...newData }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    console.log('Submitting Data:', formData);
    // Logik zum Senden der Daten an den Server
    alert('Vielen Dank! Ihre Anfrage wird bearbeitet. Sie erhalten in Kürze Ihre Offerten.');
    setCurrentStep(STEPS.length); // Zeige finale Bestätigungsseite
  };

  const variants = {
    enter: (direction: number) => ({
      x: direction > 0 ? '100%' : '-100%',
      opacity: 0
    }),
    center: {
      x: 0,
      opacity: 1
    },
    exit: (direction: number) => ({
      x: direction < 0 ? '100%' : '-100%',
      opacity: 0
    })
  };

  const renderStepContent = () => {
    return (
      <AnimatePresence initial={false} custom={direction}>
        <motion.div
          key={currentStep}
          custom={direction}
          variants={variants}
          initial="enter"
          animate="center"
          exit="exit"
          transition={{ type: 'spring', stiffness: 300, damping: 30 }}
          className="w-full"
        >
          {currentStep === 1 && <Step1 data={formData} update={updateFormData} />}
          {currentStep === 2 && <Step2 data={formData} update={updateFormData} />}
          {currentStep === 3 && <Step3 data={formData} update={updateFormData} />}
          {currentStep === 4 && <Step4 data={formData} update={updateFormData} />}
          {currentStep === 5 && <Step5 data={formData} onSubmit={handleSubmit} />}
        </motion.div>
      </AnimatePresence>
    )
  }

  return (
    <div className="bg-gray-50 min-h-screen flex flex-col font-sans">
      <header className="bg-white border-b border-gray-200 p-4 sticky top-0 z-20">
        <div className="max-w-3xl mx-auto flex justify-between items-center">
           <h1 className="text-xl font-bold text-gray-800">Umzugsofferten Schweiz</h1>
           <TrustBadges />
        </div>
      </header>

      <main className="flex-grow w-full max-w-3xl mx-auto p-4 md:p-8">
        <ProgressIndicator steps={STEPS} currentStep={currentStep} />
        <div className="relative overflow-hidden mt-8">
          {renderStepContent()}
        </div>
      </main>

      <footer className="bg-white/80 backdrop-blur-sm border-t border-gray-200 p-4 sticky bottom-0 z-20">
        <div className="max-w-3xl mx-auto flex items-center" style={{ justifyContent: currentStep > 1 ? 'space-between' : 'flex-end' }}>
          {currentStep > 1 && (
            <button onClick={handleBack} className="text-gray-600 font-semibold py-2 px-4 rounded-lg hover:bg-gray-100 flex items-center">
              <ArrowLeft size={16} className="mr-2" />
              Zurück
            </button>
          )}
          {currentStep < STEPS.length - 1 && (
            <PrimaryButton onClick={handleNext} text="Weiter" />
          )}
        </div>
      </footer>
    </div>
  );
};

// --- STEP COMPONENTS ---

const Step1 = ({ data, update }: { data: MoveDetails, update: (d: Partial<MoveDetails>) => void }) => (
  <StepWrapper title="Wo findet der Umzug statt?" subtitle="Für genaue Offerten benötigen wir Start- und Zielort.">
    <InputField label="Auszugsort (PLZ oder Ort)" value={data.fromAddress} onChange={e => update({ fromAddress: e.target.value })} placeholder="z.B. 8001 Zürich" />
    <InputField label="Einzugsort (PLZ oder Ort)" value={data.toAddress} onChange={e => update({ toAddress: e.target.value })} placeholder="z.B. 3001 Bern" />
  </StepWrapper>
);

const roomSizes = ['1-1.5 Zimmer', '2-2.5 Zimmer', '3-3.5 Zimmer', '4-4.5 Zimmer', '5+ Zimmer', 'Büro/Gewerbe'];
const Step2 = ({ data, update }: { data: MoveDetails, update: (d: Partial<MoveDetails>) => void }) => (
  <StepWrapper title="Was wird umgezogen?" subtitle="Wählen Sie die Wohnungsgrösse für eine schnelle Schätzung.">
    <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
      {roomSizes.map(size => (
        <CardSelect key={size} label={size} isSelected={data.roomSize === size} onSelect={() => update({ roomSize: size })} />
      ))}
    </div>
    <div className="mt-6">
      <label className="block text-sm font-medium text-gray-700 mb-2">Oder für eine genauere Offerte (optional):</label>
      <textarea 
        value={data.inventory} 
        onChange={e => update({ inventory: e.target.value })}
        placeholder="z.B. 1x Doppelbett, 1x Sofa, 20x Umzugskartons..."
        className="w-full p-3 border border-gray-300 rounded-lg focus:ring-blue-500 focus:border-blue-500 transition"
        rows={4}
      />
    </div>
  </StepWrapper>
);

const services = [
  { id: 'packing', label: 'Ein- & Auspackservice' },
  { id: 'assembly', label: 'Möbel-Demontage & Montage' },
  { id: 'cleaning', label: 'Endreinigung mit Abnahmegarantie' },
  { id: 'storage', label: 'Möbellagerung' },
];
const Step3 = ({ data, update }: { data: MoveDetails, update: (d: Partial<MoveDetails>) => void }) => {
  const toggleService = (serviceId: string) => {
    const newServices = data.services.includes(serviceId)
      ? data.services.filter(s => s !== serviceId)
      : [...data.services, serviceId];
    update({ services: newServices });
  };

  return (
    <StepWrapper title="Benötigen Sie weitere Hilfe?" subtitle="Buchen Sie das Rundum-Sorglos-Paket.">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {services.map(service => (
          <CardSelect key={service.id} label={service.label} isSelected={data.services.includes(service.id)} onSelect={() => toggleService(service.id)} />
        ))}
      </div>
    </StepWrapper>
  );
};

const Step4 = ({ data, update }: { data: MoveDetails, update: (d: Partial<MoveDetails>) => void }) => (
  <StepWrapper title="Wann und für wen?" subtitle="Nur noch wenige Angaben bis zu Ihren Offerten.">
    <InputField label="Wunschdatum des Umzugs" type="date" value={data.moveDate} onChange={e => update({ moveDate: e.target.value })} />
    <div className="flex items-center my-4">
      <input id="flexible-date" type="checkbox" checked={data.dateIsFlexible} onChange={e => update({ dateIsFlexible: e.target.checked })} className="h-4 w-4 text-blue-600 border-gray-300 rounded focus:ring-blue-500" />
      <label htmlFor="flexible-date" className="ml-2 block text-sm text-gray-900">Mein Datum ist flexibel</label>
    </div>
    <InputField label="Vollständiger Name" value={data.name} onChange={e => update({ name: e.target.value })} placeholder="Max Muster" />
    <InputField label="E-Mail-Adresse" type="email" value={data.email} onChange={e => update({ email: e.target.value })} placeholder="max.muster@email.ch" />
    <InputField label="Telefonnummer (für Rückfragen)" type="tel" value={data.phone} onChange={e => update({ phone: e.target.value })} placeholder="079 123 45 67" />
    <p className="text-xs text-gray-500 mt-4">Ihre Daten sind sicher und werden nur zur Angebotserstellung an geprüfte Umzugsfirmen weitergegeben. Kostenlos und unverbindlich.</p>
  </StepWrapper>
);

const Step5 = ({ data, onSubmit }: { data: MoveDetails, onSubmit: (e: React.FormEvent) => void }) => {
  const summaryItems = useMemo(() => [
    { label: 'Von', value: data.fromAddress },
    { label: 'Nach', value: data.toAddress },
    { label: 'Umfang', value: data.roomSize || 'Details siehe Liste' },
    { label: 'Services', value: data.services.length > 0 ? data.services.join(', ') : 'Keine' },
    { label: 'Datum', value: `${data.moveDate} ${data.dateIsFlexible ? '(flexibel)' : ''}` },
  ], [data]);

  return (
    <StepWrapper title="Fast geschafft!" subtitle="Bitte prüfen Sie Ihre Angaben und holen Sie Ihre Offerten ein.">
