import React from 'react';
import { Check } from 'lucide-react';

type Step = { id: number; name: string; icon: React.ElementType };

interface ProgressIndicatorProps {
  steps: Step[];
  currentStep: number;
}

export const ProgressIndicator: React.FC<ProgressIndicatorProps> = ({ steps, currentStep }) => {
  return (
    <nav aria-label="Fortschritt">
      <ol className="flex items-center justify-between">
        {steps.map((step, index) => {
          const isCompleted = currentStep > step.id;
          const isCurrent = currentStep === step.id;
          const Icon = step.icon;

          return (
            <React.Fragment key={step.id}>
              <li className="relative flex flex-col items-center text-center w-20">
                <div
                  className={`flex items-center justify-center w-10 h-10 rounded-full border-2 transition-all duration-300 ${
                    isCompleted
                      ? 'bg-blue-600 border-blue-600 text-white'
                      : isCurrent
                      ? 'border-blue-600 bg-white'
                      : 'border-gray-300 bg-gray-50'
                  }`}>
                  {isCompleted ? <Check size={20} /> : <Icon size={20} className={isCurrent ? 'text-blue-600' : 'text-gray-400'}/>}
                </div>
                <p className={`mt-2 text-xs font-semibold ${isCurrent ? 'text-blue-600' : 'text-gray-500'}`}>{step.name}</p>
              </li>
              {index < steps.length - 1 && (
                <div className="flex-1 h-0.5 bg-gray-200 mx-2">
                  <div style={{ width: isCompleted || isCurrent ? '100%' : '0%' }} className={`h-full bg-blue-600 transition-all duration-500 ${isCompleted ? '' : 'delay-300'}`}></div>
                </div>
              )}
            </React.Fragment>
          );
        })}
      </ol>
    </nav>
  );
};

