import React, { useState, useMemo, FC, ReactNode } from 'react';

// --- TYPE DEFINITIONS ---
type Service = 'packing' | 'assembly' | 'cleaning';

interface FormData {
  fromAddress: string;
  toAddress: string;
  moveDate: string;
  inventoryType: 'quick' | 'detailed';
  quickInventorySize: string; // e.g., '2.5-zimmer'
  detailedInventory: { [key: string]: number };
  services: Service[];
  contact: {
    name: string;
    email: string;
    phone: string;
  };
}

// --- SHARED COMPONENTS (Implementation below in sharedComponents section) ---

// For the purpose of this self-contained component, we declare the props for shared components.
// The actual implementation is provided in the `sharedComponents` JSON array.

interface PrimaryButtonProps {
  onClick: () => void;
  children: ReactNode;
  disabled?: boolean;
  className?: string;
}
const PrimaryButton: FC<PrimaryButtonProps> = ({ onClick, children, disabled, className }) => (
    <button onClick={onClick} disabled={disabled} className={`primary-button ${className || ''}`}>{children}</button>
);

interface TrustBadgesProps {}
const TrustBadges: FC<TrustBadgesProps> = () => <div className="trust-badges-container">...</div>;

interface StickyFooterProps {
    children: ReactNode;
}
const StickyFooter: FC<StickyFooterProps> = ({ children }) => <div className="sticky-footer">{children}</div>;

interface ProgressBarProps {
    currentStep: number;
    totalSteps: number;
}
const ProgressBar: FC<ProgressBarProps> = ({ currentStep, totalSteps }) => <div className="progress-bar-container">...</div>;

interface InputFieldProps {
    label: string;
    value: string;
    onChange: (e: React.ChangeEvent<HTMLInputElement>) => void;
    placeholder?: string;
    type?: string;
    required?: boolean;
}
const InputField: FC<InputFieldProps> = ({ label, value, onChange, placeholder, type, required }) => <div className="input-field-container">...</div>;


// --- STYLES (CSS-in-JS approach for self-containment) ---
const styles = `
  :root {
    --primary-color: #007bff; /* Vibrant Blue for CTAs */
    --secondary-color: #f8f9fa; /* Light grey background */
    --text-color: #212529; /* Dark text */
    --border-color: #dee2e6;
    --success-color: #28a745;
    --white-color: #ffffff;
    --font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
  }
  .ultimate-flow-container {
    font-family: var(--font-family);
    background-color: var(--secondary-color);
    color: var(--text-color);
    max-width: 800px;
    margin: 0 auto;
    padding: 20px;
    padding-bottom: 120px; /* Space for sticky footer */
  }
  .step-header {
    text-align: center;
    margin-bottom: 2rem;
  }
  .step-header h2 { font-size: 1.8rem; margin-bottom: 0.5rem; }
  .step-header p { font-size: 1.1rem; color: #6c757d; }
  .step-content { background-color: var(--white-color); border: 1px solid var(--border-color); border-radius: 8px; padding: 2rem; }
  .form-group { margin-bottom: 1.5rem; }
  .form-group label { display: block; font-weight: 600; margin-bottom: 0.5rem; }
  .primary-button { background-color: var(--primary-color); color: var(--white-color); border: none; padding: 12px 24px; font-size: 1rem; font-weight: 600; border-radius: 50px; cursor: pointer; transition: background-color 0.2s; width: 100%; }
  .primary-button:hover { background-color: #0056b3; }
  .primary-button:disabled { background-color: #a0c7ff; cursor: not-allowed; }

  /* Responsive Layout */
  @media (min-width: 768px) {
    .primary-button { width: auto; }
    .step-content { display: flex; gap: 2rem; }
    .step-content > div { flex: 1; }
  }
`;

// --- MAIN COMPONENT ---

export const UltimateFlowV1: FC = () => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<FormData>({
    fromAddress: '',
    toAddress: '',
    moveDate: '',
    inventoryType: 'quick',
    quickInventorySize: '2.5',
    detailedInventory: {},
    services: [],
    contact: { name: '', email: '', phone: '' },
  });

  const totalSteps = 4;

  const handleNext = () => setStep((prev) => Math.min(prev + 1, totalSteps));
  const handleBack = () => setStep((prev) => Math.max(prev - 1, 1));

  const updateFormData = (field: keyof FormData, value: any) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
  };

  const estimatedPrice = useMemo(() => {
      // Dummy price calculation for demonstration
      let basePrice = 500;
      if (formData.quickInventorySize === '3.5') basePrice += 300;
      if (formData.quickInventorySize === '4.5') basePrice += 600;
      formData.services.forEach(service => {
          if(service === 'packing') basePrice += 250;
          if(service === 'cleaning') basePrice += 400;
          if(service === 'assembly') basePrice += 150;
      });
      return `CHF ${basePrice} - ${basePrice + 300}`;
  }, [formData.quickInventorySize, formData.services]);

  const renderStepContent = () => {
    switch (step) {
      case 1:
        return (
          <div className="step-content">
            <div>
                <InputField 
                    label="Auszugsadresse"
                    value={formData.fromAddress}
                    onChange={(e) => updateFormData('fromAddress', e.target.value)}
                    placeholder="z.B. Bahnhofstrasse 1, 8001 Zürich"
                    required
                />
                <InputField 
                    label="Einzugsadresse"
                    value={formData.toAddress}
                    onChange={(e) => updateFormData('toAddress', e.target.value)}
                    placeholder="z.B. Hauptgasse 5, 3001 Bern"
                    required
                />
                <InputField 
                    label="Wunschdatum"
                    value={formData.moveDate}
                    onChange={(e) => updateFormData('moveDate', e.target.value)}
                    type="date"
                    required
                />
            </div>
          </div>
        );
      case 2:
         return (
          <div className="step-content" style={{flexDirection: 'column'}}>
            {/* Add logic for detailed inventory here */}
            <div className="form-group">
                <label>Wohnungsgrösse (Schnellauswahl)</label>
                <select value={formData.quickInventorySize} onChange={e => updateFormData('quickInventorySize', e.target.value)} style={{width: '100%', padding: '10px', borderRadius: '5px', border: '1px solid var(--border-color)'}}>
                    <option value="1.5">1-1.5 Zimmer</option>
                    <option value="2.5">2-2.5 Zimmer</option>
                    <option value="3.5">3-3.5 Zimmer</option>
                    <option value="4.5">4-4.5 Zimmer</option>
                    <option value="5.5">5+ Zimmer</option>
                </select>
            </div>
            <p style={{textAlign: 'center', margin: '1rem 0'}}>oder</p>
            <PrimaryButton onClick={() => alert('Detail-Inventar öffnet sich hier.')} className='secondary-button'>Detaillierte Inventarliste ausfüllen</PrimaryButton>
          </div>
        );
      case 3:
        const toggleService = (service: Service) => {
            const newServices = formData.services.includes(service)
                ? formData.services.filter(s => s !== service)
                : [...formData.services, service];
            updateFormData('services', newServices);
        };
        return (
            <div className="step-content" style={{flexDirection: 'column'}}>
                {['packing', 'assembly', 'cleaning'].map(s => (
                    <div key={s} style={{display: 'flex', alignItems: 'center', marginBottom: '1rem'}}>
                        <input type="checkbox" id={s} checked={formData.services.includes(s as Service)} onChange={() => toggleService(s as Service)} style={{width: '20px', height: '20px', marginRight: '10px'}}/>
                        <label htmlFor={s} style={{marginBottom: '0', textTransform: 'capitalize'}}> {s === 'packing' ? 'Ein- & Auspackservice' : s === 'assembly' ? 'Möbel De- & Montage' : 'Endreinigung mit Abnahmegarantie'} </label>
                    </div>
                ))}
            </div>
        );
      case 4:
         return (
            <div className="step-content">
                <div>
                    <p style={{marginBottom: '1rem'}}><strong>Ihre Anfrage-Zusammenfassung:</strong></p>
                    <ul>
                        <li><strong>Von:</strong> {formData.fromAddress || 'N/A'}</li>
                        <li><strong>Nach:</strong> {formData.toAddress || 'N/A'}</li>
                        <li><strong>Grösse:</strong> {formData.quickInventorySize} Zimmer</li>
                        <li><strong>Services:</strong> {formData.services.join(', ') || 'Keine'}</li>
                    </ul>
                </div>
                <div>
                    <InputField label="Name" value={formData.contact.name} onChange={(e) => updateFormData('contact', {...formData.contact, name: e.target.value})} required />
                    <InputField label="E-Mail" type="email" value={formData.contact.email} onChange={(e) => updateFormData('contact', {...formData.contact, email: e.target.value})} required />
                    <InputField label="Telefon" type="tel" value={formData.contact.phone} onChange={(e) => updateFormData('contact', {...formData.contact, phone: e.target.value})} />
                    <TrustBadges />
                </div>
            </div>
        );
      default: return null;
    }
  };

  const isNextDisabled = () => {
      if(step === 1) return !formData.fromAddress || !formData.toAddress || !formData.moveDate;
      if(step === 4) return !formData.contact.name || !formData.contact.email;
      return false;
  }

  return (
    <>
      <style>{styles}</style>
      <div className="ultimate-flow-container">
        <ProgressBar currentStep={step} totalSteps={totalSteps} />
        <div className="step-header">
          {step === 1 && <><h2>Wohin dürfen wir für Sie umziehen?</h2><p>Starten Sie hier Ihre unverbindliche Anfrage in 2 Minuten.</p><TrustBadges /></>}
          {step === 2 && <><h2>Was soll umgezogen werden?</h2><p>Je genauer Ihre Angaben, desto präziser die Angebote.</p></>}
          {step === 3 && <><h2>Benötigen Sie zusätzliche Hilfe?</h2><p>Wählen Sie unsere Sorglos-Pakete.</p></>}
          {step === 4 && <><h2>Fast geschafft!</h2><p>Kostenlose & unverbindliche Angebote von geprüften Firmen erhalten.</p></>}
        </div>

        {renderStepContent()}

        <StickyFooter>
          <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', width: '100%'}}>
             <div style={{fontWeight: 'bold'}}>Preis-Schätzung: <span style={{color: 'var(--success-color)'}}>{estimatedPrice}</span></div>
             <div>
                {step > 1 && <button onClick={handleBack} style={{marginRight: '1rem', background: 'none', border: 'none', color: 'var(--primary-color)', cursor: 'pointer'}}>Zurück</button>}
                {step < totalSteps && <PrimaryButton onClick={handleNext} disabled={isNextDisabled()}>Weiter</PrimaryButton>}
                {step === totalSteps && <PrimaryButton onClick={() => alert('Angebote werden angefordert!')} disabled={isNextDisabled()}>Angebote erhalten</PrimaryButton>}
             </div>
          </div>
        </StickyFooter>
      </div>
    </>
  );
};

