export const HelvetiaFlowV1 = () => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<FormData>(initialFormData);
  const TOTAL_STEPS = 6; 

  const updateFormData = (data: Partial<FormData>) => {
    setFormData(prev => ({ ...prev, ...data }));
  };

  const nextStep = () => setStep(s => Math.min(s + 1, TOTAL_STEPS));
  const prevStep = () => setStep(s => Math.max(s - 1, 1));

  const isFinalStep = step === TOTAL_STEPS - 1;

  const renderStep = () => {
    switch (step) {
      case 1: return <Step1_Start data={formData} update={updateFormData} />;
      case 2: return <Step2_Logistics data={formData} update={updateFormData} />;
      case 3: return <Step3_Inventory data={formData} update={updateFormData} />;
      case 4: return <Step4_Services data={formData} update={updateFormData} />;
      case 5: return <Step5_Summary data={formData} update={updateFormData} setStep={setStep} />;
      case 6: return <Step6_Dashboard />;
      default: return <Step1_Start data={formData} update={updateFormData} />;
    }
  };

  return (
    <div className="max-w-2xl mx-auto p-4 sm:p-6 font-sans bg-white shadow-lg rounded-lg my-8">
      <header className="mb-6">
        {step < TOTAL_STEPS && <ProgressBar currentStep={step} totalSteps={TOTAL_STEPS -1} />}
        {step === 1 && <TrustBadges />}
      </header>

      <main className="min-h-[400px]">
        {renderStep()}
      </main>

      {step < TOTAL_STEPS && (
        <footer className="mt-8 pt-4 border-t sticky bottom-0 bg-white py-4">
          <div className="flex items-center justify-between">
            <div>
              {step > 1 && <button onClick={prevStep} className="py-2 px-4 rounded-lg text-gray-600 hover:bg-gray-100">Zurück</button>}
            </div>
            <DynamicPriceIndicator formData={formData} />
            <div>
              <button onClick={nextStep} className="py-3 px-6 bg-blue-600 text-white font-bold rounded-lg shadow-md hover:bg-blue-700">
                {isFinalStep ? 'Jetzt kostenlose Offerten anfordern' : 'Weiter'}
              </button>
            </div>
          </div>
          {isFinalStep && <p className="text-xs text-center text-gray-500 mt-2">100% kostenlos & unverbindlich</p>}
        </footer>
      )}
    </div>
  );
};

