type FieldProps = {
  label: string;
  name: string;
  type?: React.HTMLInputTypeAttribute;
  value: string;
  onChange: (v: string) => void;
  placeholder?: string;
  error?: string;
  autoComplete?: string;
  inputMode?: React.HTMLAttributes<HTMLInputElement>["inputMode"];
};

export function Field({
  label,
  name,
  type = "text",
  value,
  onChange,
  placeholder,
  error,
  autoComplete,
  inputMode,
}: FieldProps) {
  return (
    <label className="block">
      <span className="text-sm font-medium text-gray-900">{label}</span>
      <input
        name={name}
        type={type}
        value={value}
        inputMode={inputMode}
        autoComplete={autoComplete}
        onChange={(e) => onChange(e.target.value)}
        placeholder={placeholder}
        className={[
          "mt-2 h-12 w-full rounded-xl border px-4 text-base",
          "focus:outline-none focus:ring-2 focus:ring-gray-900",
          error ? "border-red-500" : "border-gray-300",
        ].join(" ")}
      />
      {error ? <p className="mt-1 text-xs text-red-600">{error}</p> : <div className="h-4" />}
    </label>
  );
}

V1 – Control Flow
1) 3 kritischste UX-Probleme

CTA/Next Step nicht permanent sichtbar (Mobile) → Nutzer verlieren den “Weiter”-Button, Scroll-Friction.

Zu viel Form-Friction zu früh (zu viele Pflichtfelder, unklare Validierung, kein Autofill) → Drop-off in Step 1/2.

Zu wenig Trust vor Dateneingabe → “Warum soll ich Telefonnummer/Adresse geben?” → Abbruch.

2) Konkrete Verbesserungen (React/Tailwind)

Zielbild: 4 Steps → 2 Steps (Umzugsdetails → Kontakt) + Sticky CTA + Trust direkt oben.

