Zielbild: “Friction” nach vorne ziehen? Nein: Friction eliminieren. End-Step als 1 Screen, Autofill, klare Consent-Microcopy.

function ContactStep({ onSubmit }: { onSubmit: (d: { name: string; email: string; phone: string }) => void }) {
  const [name, setName] = React.useState("");
  const [email, setEmail] = React.useState("");
  const [phone, setPhone] = React.useState("");
  const canSubmit = name.trim().length > 1 && email.includes("@") && phone.trim().length >= 8;

  return (
    <div className="pb-28">
