          label="Name"
          name="name"
          value={name}
          onChange={setName}
          autoComplete="name"
          placeholder="Vor- und Nachname"
        />
        <Field
          label="E-Mail"
          name="email"
          type="email"
          value={email}
          onChange={setEmail}
          autoComplete="email"
          placeholder="name@beispiel.ch"
          inputMode="email"
        />
        <Field
          label="Telefon (für Rückfragen)"
          name="phone"
          type="tel"
          value={phone}
          onChange={setPhone}
          autoComplete="tel"
          placeholder="+41 ..."
          inputMode="tel"
        />

        <p className="text-xs text-gray-600">
          Mit Klick auf “Offerten erhalten” erlaubst du uns, deine Anfrage an passende, geprüfte Umzugsfirmen
          zur Offertstellung weiterzugeben. Kein Abo, keine Verpflichtung.
        </p>
      </div>

      <StickyFooterCTA
        primaryLabel="Offerten erhalten"
        onPrimary={() => onSubmit({ name, email, phone })}
