              <p className="text-base font-semibold">Gratis Offerten</p>
              <span className="text-xs rounded-full border px-2 py-1">Empfohlen</span>
            </div>
            <ul className="mt-2 list-disc pl-5 text-sm text-gray-700 space-y-1">
              <li>Unverbindlich</li>
              <li>Geprüfte Umzugsfirmen</li>
              <li>Schneller Vergleich</li>
            </ul>
          </button>

          <button
